import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { updateCourse, deleteCourse } from "../courseReducer";

function EditCourse() {
  const { id } = useParams();
  const [name, setName] = useState("");
  const [subjectId, setSubjectId] = useState("");
  const [classId, setClassId] = useState("");
  const [deadline, setDeadline] = useState("");
  const [file, setFile] = useState(null);
  const [existingFiles, setExistingFiles] = useState([]);
  const [course, setCourse] = useState(null);
  const [subjects, setSubjects] = useState([]);
  const [classes, setClasses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`http://localhost:3001/courses/${id}`)
      .then((res) => res.json())
      .then((data) => {
        setCourse(data);
        setName(data.name);
        setSubjectId(data.subjectId);
        setClassId(data.classId);
        setDeadline(data.deadline);
      })
      .catch((error) => toast.error("Ошибка загрузки курса"));
    fetch(`http://localhost:3001/files?courseId=${id}`)
      .then((res) => res.json())
      .then((data) => setExistingFiles(data))
      .catch((error) => toast.error("Ошибка загрузки файлов"));
    fetch(`http://localhost:3001/teacher_subjects?teacherId=${user.id}`)
      .then((res) => res.json())
      .then((data) => {
        const subjectIds = data.map((ts) => ts.subjectId);
        fetch(`http://localhost:3001/subjects?id=${subjectIds.join("&id=")}`)
          .then((res) => res.json())
          .then((subjects) => setSubjects(subjects));
      });
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data));
  }, [id, user.id]);

  async function handleSubmit(e) {
    e.preventDefault();
    let filePath = null;

    if (file) {
      const allowedTypes = ["image/jpeg", "image/png", "application/pdf"];
      const maxSize = 5 * 1024 * 1024;

      if (!allowedTypes.includes(file.type)) {
        toast.error("Допустимы только изображения (JPEG, PNG) или PDF-файлы");
        return;
      }

      if (file.size > maxSize) {
        toast.error("Файл слишком большой. Максимальный размер: 5 МБ");
        return;
      }

      const formData = new FormData();
      formData.append("file", file);
      try {
        const response = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const data = await response.json();
        if (response.ok) {
          filePath = data.filePath;
        } else {
          toast.error("Не удалось загрузить файл");
          return;
        }
      } catch (error) {
        toast.error("Сетевая ошибка при загрузке файла");
        return;
      }
    }

    try {
      const updatedCourse = {
        id: parseInt(id),
        name,
        subjectId: parseInt(subjectId),
        classId: parseInt(classId),
        teacherId: user.id,
        deadline,
      };
      const response = await fetch(`http://localhost:3001/courses/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedCourse),
      });

      if (response.ok) {
        if (filePath) {
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: parseInt(id),
              filePath,
              fileName: file.name,
            }),
          });
        }
        dispatch(updateCourse(updatedCourse));
        toast.success("Курс успешно обновлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось обновить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при обновлении курса");
    }
  }

  async function handleDelete() {
    try {
      const enrollmentsResponse = await fetch(
        `http://localhost:3001/enrollments?courseId=${id}`
      );
      const enrollments = await enrollmentsResponse.json();
      for (const enrollment of enrollments) {
        await fetch(`http://localhost:3001/enrollments/${enrollment.id}`, {
          method: "DELETE",
        });
      }
      const filesResponse = await fetch(`http://localhost:3001/files?courseId=${id}`);
      const files = await filesResponse.json();
      for (const file of files) {
        await fetch(`http://localhost:3001/files/${file.id}`, { method: "DELETE" });
      }
      const response = await fetch(`http://localhost:3001/courses/${id}`, {
        method: "DELETE",
      });

      if (response.ok) {
        dispatch(deleteCourse(parseInt(id)));
        toast.success("Курс успешно удален!");
        navigate("/courses");
      } else {
        toast.success("Курс успешно удален!");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении курса");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1 className="title">Доступ запрещен</h1></div>;
  }

  if (course && parseInt(course.teacherId) !== parseInt(user.id)) {
    return (
      <div className="container mt-5">
        <h1 className="title">Вы не можете редактировать этот курс</h1>
      </div>
    );
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-8">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Редактировать курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">
                    Название курса
                  </label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="subject" className="form-label">
                    Предмет
                  </label>
                  <select
                    id="subject"
                    className="form-select"
                    value={subjectId}
                    onChange={(e) => setSubjectId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите предмет --</option>
                    {subjects.map((subject) => (
                      <option key={subject.id} value={subject.id}>
                        {subject.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="class" className="form-label">
                    Класс
                  </label>
                  <select
                    id="class"
                    className="form-select"
                    value={classId}
                    onChange={(e) => setClassId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите класс --</option>
                    {classes.map((cls) => (
                      <option key={cls.id} value={cls.id}>
                        {cls.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="deadline" className="form-label">
                    Дедлайн курса
                  </label>
                  <input
                    type="date"
                    id="deadline"
                    className="form-control"
                    value={deadline}
                    onChange={(e) => setDeadline(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">
                    Добавить новый файл (JPEG, PNG, PDF, до 5 МБ)
                  </label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                {existingFiles.length > 0 && (
                  <div className="mb-3">
                    <h5>Существующие файлы:</h5>
                    <ul className="list-group">
                      {existingFiles.map((f) => (
                        <li key={f.id} className="list-group-item">
                          <a href={`http://localhost:3002${f.filePath}`} download>
                            {f.fileName}
                          </a>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
                <div className="d-flex justify-content-between">
                  <button type="submit" className="btn btn-primary w-100 me-2">
                    Обновить
                  </button>
                  <button
                    type="button"
                    onClick={handleDelete}
                    className="btn btn-danger w-100"
                  >
                    Удалить курс
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EditCourse;
